def check_postgresql(hostname, user, password):
    try:
        conn=psycopg2.connect( host=hostname, user= user, password= password)
        db_up.labels(host=hostname, user=user, password=password).set(1)  # set the metric value to 1 if database is up
    except Exception:
        db_up.labels(host=hostname, user=user, password=password).set(0)  # set the metric value to 0 if there's an error
        
